class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> cnt(1 << 10, 0);
        for (int i = 0; i < n; i++) {
            cnt[nums[i]]++;
        }
        int res = n;
        for (int mask = 0; mask < 1 << 10; mask++) {
            int cur = 0;
            for (int i = 0; i < 10; i++) {
                if (((mask >> i) & 1) == 0) {
                    cur += cnt[(1 << 10) - 1 - (1 << i)];
                }
            }
            res = min(res, cur);
        }
        return res;
    }
};
